INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0ea3e69b-73a3-457d-bf04-2c45eb1e66f3$tag$, $tag$2026011400162$tag$, $tag$Raylla Gleyce (5586994452978)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"14/01/2026 15:41:53"},{"role":"client","text":"🌟 Boa tarde Raylla Gleyce! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 15:41:54"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 15:41:58"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 15:42:02"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 15:42:06"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 15:42:12"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 15:42:18"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 15:42:19"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 15:42:32"},{"role":"client","text":"✅ Obrigado, Raylla Gleyce! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 15:42:33"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 15:42:37"},{"role":"client","text":"Fundação Cidade Viva","time":"14/01/2026 15:43:01"},{"role":"client","text":"Boa tarde, Raylla Gleyce! 🙌 Obrigado(a) por entrar em contato com a Fundação Cidade Viva.","time":"14/01/2026 15:43:02"},{"role":"client","text":"Selecione a opção abaixo para o que deseja:","time":"14/01/2026 15:43:06"},{"role":"client","text":"Mais informações","time":"14/01/2026 15:43:30"},{"role":"client","text":"Ótimo, Raylla Gleyce! \nTemos muitas informações para compartilhar. 😊","time":"14/01/2026 15:43:32"},{"role":"client","text":"Por favor, selecione a opção abaixo sobre o que você mais deseja saber:","time":"14/01/2026 15:43:36"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 15:43:39"},{"role":"client","text":"Desculpe, não entendi a sua solicitação.\nPor favor selecione a opção no menu abaixo:","time":"14/01/2026 15:43:41"},{"role":"client","text":"Por favor, selecione a opção abaixo sobre o que você mais deseja saber:","time":"14/01/2026 15:43:45"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 15:43:47"},{"role":"client","text":"Selecione a opção abaixo para o que deseja:","time":"14/01/2026 15:43:51"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 15:43:54"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 15:43:55"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 15:44:01"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"14/01/2026 15:44:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 15:44:02"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 15:44:16"},{"role":"client","text":"Olá! Raylla Gleyce!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 15:44:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 15:44:20"},{"role":"client","text":"Saber sobre os cursos","time":"14/01/2026 15:44:40"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"14/01/2026 15:44:44"},{"role":"client","text":"Pós-Graduação","time":"14/01/2026 15:44:55"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"14/01/2026 15:44:59"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 15:45:15"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"14/01/2026 15:45:16"},{"role":"client","text":"Educação Cristã Clássica","time":"14/01/2026 15:45:17"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"14/01/2026 15:45:18"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"14/01/2026 15:45:20"},{"role":"client","text":"Educação Cristã Clássica","time":"14/01/2026 15:45:35"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"14/01/2026 15:45:35"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"14/01/2026 15:45:39"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"14/01/2026 15:46:15"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"14/01/2026 15:46:18"},{"role":"client","text":"Gostaria de saber os preços","time":"14/01/2026 15:49:05"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 15:51:01"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"14/01/2026 15:51:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"14/01/2026 15:51:45","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"14/01/2026 15:51:54","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Vai ter turma em agosto?","time":"14/01/2026 15:56:18"},{"role":"client","text":"Quero me organizar pra iniciar no próximo semestre","time":"14/01/2026 15:56:34"},{"role":"agent","text":"*Karina Pimentel:* Em Setembro abrirá nova turma!","time":"14/01/2026 16:35:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Certo 🥹","time":"14/01/2026 16:37:57"},{"role":"client","text":"Obrigada","time":"14/01/2026 16:38:01"},{"role":"agent","text":"*Karina Pimentel:*  \n     Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"14/01/2026 16:41:44","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nRaylla Gleyce, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 16:41:47"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"14/01/2026 16:41:48"},{"role":"client","text":"Raylla Gleyce, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"14/01/2026 16:56:49"}]