INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$167e6713-13b6-46ed-a577-c3f48593ef5a$tag$, $tag$2026011500016$tag$, $tag$Márcia Regina (5561999774390)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Psicoteologia e quero mais informações.","time":"15/01/2026 03:07:56"},{"role":"client","text":"🌟 Bom dia Márcia Regina! Que alegria ter você aqui com a gente! 🙌","time":"15/01/2026 03:07:57"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"15/01/2026 03:08:01"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"15/01/2026 03:08:04"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"15/01/2026 03:08:08"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"15/01/2026 03:08:14"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"15/01/2026 03:08:20"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"15/01/2026 03:08:23"},{"role":"client","text":"Sim, concordo","time":"15/01/2026 03:17:28"},{"role":"client","text":"✅ Obrigado, Márcia Regina! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"15/01/2026 03:17:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"15/01/2026 03:17:32"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"15/01/2026 03:19:15"},{"role":"client","text":"Olá! Márcia Regina!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"15/01/2026 03:19:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"15/01/2026 03:19:20"},{"role":"client","text":"Saber sobre os cursos","time":"15/01/2026 03:19:39"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"15/01/2026 03:19:44"},{"role":"client","text":"Pós-Graduação","time":"15/01/2026 03:20:37"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"15/01/2026 03:20:41"},{"role":"client","text":"Psicoteologia","time":"15/01/2026 03:38:04"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"15/01/2026 03:38:05"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"15/01/2026 03:38:09"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"15/01/2026 03:47:18"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"15/01/2026 03:47:19"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"15/01/2026 03:47:20"},{"role":"client","text":"Queria saber valores e tempo","time":"15/01/2026 04:29:32"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"15/01/2026 08:42:43"},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"15/01/2026 08:43:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Olá","time":"15/01/2026 08:43:18"},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Fevereiro 2026!","time":"15/01/2026 08:43:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Você pode me mandar as matérias?","time":"15/01/2026 08:45:07"},{"role":"client","text":"E quanto tempo tenho para terminar?","time":"15/01/2026 09:01:45"},{"role":"agent","text":"*Karina Pimentel:* Módulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão","time":"15/01/2026 09:03:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Qual o tempo para terminar?","time":"15/01/2026 09:20:03"},{"role":"client","text":"Oi, já preenchi meus dados na página lideranca Crista e quero mais informaçõe