INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c7c40995-9432-406d-9c04-67dcda2b3353$tag$, $tag$2026011500018$tag$, $tag$Cristiano Santos (5579999107010)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Formacao Politica e quero mais informações.","time":"15/01/2026 04:51:04"},{"role":"client","text":"🌟 Bom dia Cristiano Santos! Que alegria ter você aqui com a gente! 🙌","time":"15/01/2026 04:51:05"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"15/01/2026 04:51:09"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"15/01/2026 04:51:13"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"15/01/2026 04:51:17"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"15/01/2026 04:51:22"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"15/01/2026 04:51:28"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"15/01/2026 04:51:29"},{"role":"client","text":"Sim, concordo","time":"15/01/2026 04:51:57"},{"role":"client","text":"✅ Obrigado, Cristiano Santos! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"15/01/2026 04:51:58"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"15/01/2026 04:52:02"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"15/01/2026 04:52:46"},{"role":"client","text":"Olá! Cristiano Santos!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"15/01/2026 04:52:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"15/01/2026 04:52:51"},{"role":"client","text":"Saber sobre os cursos","time":"15/01/2026 04:53:05"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"15/01/2026 04:53:10"},{"role":"client","text":"Pós-Graduação","time":"15/01/2026 04:53:23"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"15/01/2026 04:53:27"},{"role":"client","text":"Ciência Política","time":"15/01/2026 04:54:02"},{"role":"client","text":"Quer compreender os fundamentos políticos a partir de uma cosmovisão cristã?\n 📘 Curso voltado para quem atua ou deseja atuar em política, gestão pública ou liderança institucional\n 📅 Início em agosto\n 💻 Estudo online e contextualizado\n","time":"15/01/2026 04:54:03"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"15/01/2026 04:54:07"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"15/01/2026 04:54:23"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"15/01/2026 04:54:24"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"15/01/2026 04:54:25"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"15/01/2026 08:42:51"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"15/01/2026 08:43:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Pós-Graduação em Formação Politica e Atuação Pública*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\nNossa carga horária é de 480 h.\n\nDISCIPLINAS\nContamos com um total de 11 disciplinas.\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"15/01/2026 08:43:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Formação Politica e Atuação Pública - DISCIPLINAS DO CURSO:\n\nBASE: COSMOVISÃO CRISTÃ\nCosmovisão Cristã e Política \nIdeologias Políticas Contemporâneas\nÉtica Cristã \n\nBASE: CIÊNCIA POLÍTICA\nTeorias políticas clássicas\nTeoria política reformacional\nPolítica e Ordem Jurídica \nCidadania e Ação Cívica \n\nBASE: ATUAÇÃO PÚBLICA\nPoder Executivo \nPoder Legislativo\nPoder Judiciário \n\nDISCIPLINA FACULTATIVA\nMentoria para Candidatos a Mandatos Eletivos - Marketing e Posicionamento\n\nObs: Professores sujeitos a alterações. ","time":"15/01/2026 08:43:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Formação Politica e Atuação Pública  está em 16 mensalidades de *R$ 359,37*. Desconto especial de e *black November* esta com 70% de desconto e as mensalidades ficam por R$ 107,81.\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Março/2026.\n\n\n📌 Realize sua matrícula no link: \n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"15/01/2026 08:43:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nCristiano Santos, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"16/01/2026 08:14:24"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"16/01/2026 08:14:25"},{"role":"client","text":"Cristiano Santos, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"16/01/2026 08:29:26"}]$tag$, $tag$2026-01-15 04:51:04+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
