INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$489c2ccf-2d54-4ea4-b1db-925f6fe64f8e$tag$, $tag$2026011500144$tag$, $tag$Daniel Cezário (5511995440493)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"15/01/2026 16:17:53"},{"role":"client","text":"🌟 Boa tarde Daniel Cezário! Que alegria ter você aqui com a gente! 🙌","time":"15/01/2026 16:17:54"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"15/01/2026 16:17:57"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"15/01/2026 16:18:02"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"15/01/2026 16:18:06"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"15/01/2026 16:18:12"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"15/01/2026 16:18:18"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"15/01/2026 16:18:19"},{"role":"client","text":"Sim, concordo","time":"15/01/2026 16:19:28"},{"role":"client","text":"✅ Obrigado, Daniel Cezário! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"15/01/2026 16:19:28"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"15/01/2026 16:19:32"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"15/01/2026 16:21:27"},{"role":"client","text":"Olá! Daniel Cezário!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"15/01/2026 16:21:29"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"15/01/2026 16:21:32"},{"role":"client","text":"Saber sobre os cursos","time":"15/01/2026 16:23:31"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"15/01/2026 16:23:36"},{"role":"client","text":"Pós-Graduação","time":"15/01/2026 16:23:52"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"15/01/2026 16:23:56"},{"role":"client","text":"Novo Testamento","time":"15/01/2026 16:24:28"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"15/01/2026 16:24:29"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"15/01/2026 16:24:33"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"15/01/2026 16:25:05"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"15/01/2026 16:25:05"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"15/01/2026 16:43:17"},{"role":"client","text":"Olá","time":"15/01/2026 16:43:31"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"15/01/2026 16:43:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Muito prazer!","time":"15/01/2026 16:43:38"},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"15/01/2026 16:43:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"15/01/2026 16:43:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. \n\n🎁 Cupom de Desconto Novo Testamento: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_23\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"15/01/2026 16:44:01","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Quais requisitos","time":"15/01/2026 16:45:58"},{"role":"client","text":"?","time":"15/01/2026 16:46:00"},{"role":"agent","text":"*Thayanne Sales:* A única exigência é que você tenha qualquer graduação que seja reconhecida pelo MEC\n\nE caso não tenha nenhuma também é possível fazer, mas sai como curso livre","time":"15/01/2026 16:47:55","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi!","time":"15/01/2026 16:48:17"},{"role":"client","text":"Sobre os professores, quem são os professores atualmente dessa pós?","time":"15/01/2026 16:48:44"},{"role":"client","text":"Sei que pode ser alterado, só pra saber mesmo...","time":"15/01/2026 16:48:57"},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69694c0be567ec0a7607280c)","time":"15/01/2026 17:20:27","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Obrigado","time":"15/01/2026 18:19:14"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"16/01/2026 08:18:01","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Obrigado","time":"16/01/2026 10:31:37"},{"role":"client","text":"Ainda estou em\nProcesso decisório","time":"16/01/2026 10:31:42"},{"role":"agent","text":"*Thayanne Sales:* Compreendo","time":"16/01/2026 10:53:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"16/01/2026 10:53:33","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não, muito obrigado pela atenção","time":"16/01/2026 11:06:57"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo final de semana. ","time":"16/01/2026 11:08:56","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nDaniel Cezário, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"16/01/2026 11:09:01"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"16/01/2026 11:09:02"},{"role":"client","text":"Daniel Cezário, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"16/01/2026 11:24:03"}]$tag$, $tag$2026-01-15 16:17:53+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 10, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
