INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$741699d5-038f-4a69-a598-beef69d05ce5$tag$, $tag$2026011600052$tag$, $tag$Valdir Oliveira (5569993067601)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá","time":"16/01/2026 09:51:32"},{"role":"client","text":"🌟 Bom dia Valdir Oliveira! Que alegria ter você aqui com a gente! 🙌","time":"16/01/2026 09:51:33"},{"role":"client","text":"Bom dia","time":"16/01/2026 09:51:37"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"16/01/2026 09:51:37"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"16/01/2026 09:51:38"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"16/01/2026 09:51:41"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"16/01/2026 09:51:45"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"16/01/2026 09:51:51"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"16/01/2026 09:51:57"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"16/01/2026 09:51:58"},{"role":"client","text":"Sim, concordo","time":"16/01/2026 09:56:47"},{"role":"client","text":"✅ Obrigado, Valdir Oliveira! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"16/01/2026 09:56:48"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"16/01/2026 09:56:52"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"16/01/2026 09:57:37"},{"role":"client","text":"Olá! Valdir Oliveira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"16/01/2026 09:57:39"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"16/01/2026 09:57:43"},{"role":"client","text":"Falar com um atendente","time":"16/01/2026 09:58:09"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"16/01/2026 09:58:09"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"16/01/2026 10:05:09"},{"role":"client","text":"Oi","time":"16/01/2026 10:09:06"},{"role":"client","text":"Essa faculdade de teologia de vcs é reconhecida pelo MEC","time":"16/01/2026 10:09:53"},{"role":"client","text":"Quantos anos de estudo para a formação?","time":"16/01/2026 10:10:12"},{"role":"client","text":"Qual o valor mensal","time":"16/01/2026 10:10:26"},{"role":"client","text":"Me dê uma prévia de como funciona por gentileza","time":"16/01/2026 10:11:00"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"16/01/2026 10:42:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"16/01/2026 10:42:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Olá","time":"16/01/2026 11:43:39"},{"role":"client","text":"Muito obrigado pelas informações","time":"16/01/2026 11:43:50"},{"role":"client","text":"Vcs tem presencial em porto velho Rondônia? Ou alguém ou representante","time":"16/01/2026 11:44:40"},{"role":"agent","text":"*Karina Pimentel:* Presencial somente em João Pessoa.","time":"16/01/2026 11:45:55","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* De nada! Qualquer duvida estou a disposição!","time":"16/01/2026 11:46:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Essa faculdade é da linha teológica da igreja assembleia de Deus?","time":"16/01/2026 11:47:42"},{"role":"agent","text":"*Karina Pimentel:* Nossa base filosófica/teológica é a cosmovisão cristã, seguindo o método de interpretação das Sagradas Escrituras histórico-gramatical.\n\nSomos vinculados a fundação Cidade Viva que tem sua raiz Batista, porém somos uma Faculdade, o que difere de um seminário, o seminário tem um viés mais denominacional, acabamos tendo professores de outras denominações, Presbiteriano, Batista, Adventista, Anglicano, pois, prezamos pela integridade intelectual. São professores especializados em suas áreas.","time":"16/01/2026 11:48:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Certo obrigado","time":"16/01/2026 11:51:06"},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"16/01/2026 15:41:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nValdir Oliveira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"16/01/2026 15:41:02"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"16/01/2026 15:41:03"},{"role":"client","text":"Valdir Oliveira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"16/01/2026 15:56:04"}]$tag$, $tag$2026-01-16 09:51:32+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
